   103→const MAX_PER_PAGE: u16 = 250;
   104→
   105→#[derive(Debug, Deserialize, Validate)]
   106→pub struct ListQuery {
   107→    #[validate(custom = "validate_page")]
   108→    pub page: Option<u32>,
   109→
   110→    #[validate(custom = "validate_per_page")]
   111→    pub per_page: Option<u16>,
