   118→
   119→fn validate_page(v: &Option<u32>) -> Result<(), ValidationError> {
   120→    if let Some(page) = v {
   121→        if *page == 0 {
   122→            return Err(ValidationError::new("page_must_be_positive"));
   123→        }
   124→    }
   125→    Ok(())
   126→}
   127→
   128→fn validate_per_page(v: &Option<u16>) -> Result<(), ValidationError> {
   129→    if let Some(per_page) = v {
   130→        if *per_page == 0 || *per_page > MAX_PER_PAGE {
   131→            return Err(ValidationError::new("per_page_out_of_range"));
   132→        }
   133→    }
   134→    Ok(())
   135→}
