   167→    pub user_id: Uuid,
   168→}
   169→
   170→#[derive(Debug, Error)]
   171→pub enum AuthError {
   172→    #[error("Unauthorized")]
   173→    Unauthorized,
   174→}
   175→
   176→#[async_trait]
   177→impl<S> FromRequestParts<S> for JwtAuth
   178→where
   179→    S: Send + Sync,
   180→{
   181→    type Rejection = ApiError;
   182→
   183→    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
   184→        let TypedHeader(Authorization(bearer)) =
   185→            TypedHeader::<Authorization<Bearer>>::from_request_parts(parts, _state)
   186→                .await
   187→                .map_err(|_| ApiError::unauthorized())?;
   188→
   189→        // In real life, validate signature & claims with proper key rotation
   190→        let token_str = bearer.token();
   191→
   192→        // For demonstration, we expect "tenant:<tenant_id>:user:<user_id>"
   193→        let mut iter = token_str.split(':');
   194→        let prefix = iter.next().unwrap_or_default();
   195→        if prefix != "tenant" {
   196→            return Err(ApiError::unauthorized());
   197→        }
   198→        let tenant_id = iter
   199→            .next()
   200→            .and_then(|s| Uuid::parse_str(s).ok())
   201→            .ok_or_else(ApiError::unauthorized)?;
   202→
   203→        let prefix2 = iter.next().unwrap_or_default();
   204→        if prefix2 != "user" {
   205→            return Err(ApiError::unauthorized());
   206→        }
   207→        let user_id = iter
   208→            .next()
   209→            .and_then(|s| Uuid::parse_str(s).ok())
   210→            .ok_or_else(ApiError::unauthorized)?;
   211→
   212→        Ok(Self { tenant_id, user_id })
   213→    }
   214→}
