   252→    async fn list(
   253→        &self,
   254→        tenant_id: Uuid,
   255→        query: &ListQuery,
   256→    ) -> Result<(Vec<LedgerEntry>, u64), RepositoryError> {
   257→        let page = query.page.unwrap_or(1);
   258→        let per_page = query.per_page.unwrap_or(50) as i64;
   259→        let offset = ((page - 1) as i64) * per_page;
   260→
   261→        // Filtering
   262→        let (entries, total): (Vec<LedgerEntry>, i64) = if let Some(ref account) = query.account_code
   263→        {
   264→            let rows = sqlx::query_as::<_, LedgerEntry>(
   265→                r#"
   266→                SELECT *
   267→                FROM ledger_entries
   268→                WHERE tenant_id = $1
   269→                  AND account_code = $2
   270→                ORDER BY occurred_at DESC
   271→                OFFSET $3
   272→                LIMIT $4
   273→                "#,
   274→            )
   275→            .bind(tenant_id)
   276→            .bind(account)
   277→            .bind(offset)
   278→            .bind(per_page)
   279→            .fetch_all(&self.pool)
   280→            .await?;
   281→
   282→            let total: (i64,) = sqlx::query_as(
   283→                r#"
   284→                SELECT COUNT(*) as count
   285→                FROM ledger_entries
   286→                WHERE tenant_id = $1
   287→                  AND account_code = $2
   288→                "#,
   289→            )
   290→            .bind(tenant_id)
   291→            .bind(account)
   292→            .fetch_one(&self.pool)
   293→            .await?;
   294→
   295→            (rows, total.0)
   296→        } else {
   297→            let rows = sqlx::query_as::<_, LedgerEntry>(
   298→                r#"
   299→                SELECT *
   300→                FROM ledger_entries
   301→                WHERE tenant_id = $1
   302→                ORDER BY occurred_at DESC
   303→                OFFSET $2
   304→                LIMIT $3
   305→                "#,
   306→            )
   307→            .bind(tenant_id)
   308→            .bind(offset)
   309→            .bind(per_page)
   310→            .fetch_all(&self.pool)
   311→            .await?;
   312→
   313→            let total: (i64,) = sqlx::query_as(
   314→                r#"
   315→                SELECT COUNT(*) as count
   316→                FROM ledger_entries
   317→                WHERE tenant_id = $1
   318→                "#,
   319→            )
   320→            .bind(tenant_id)
   321→            .fetch_one(&self.pool)
   322→            .await?;
   323→
   324→            (rows, total.0)
   325→        };
   326→
   327→        Ok((entries, total as u64))
   328→    }
   329→}
