\n        let sample_query = LedgerEntryQuery {\n            page_size: Some(10),\n            page: Some(1),\n            account_id: None,\n            from_date: None,\n            to_date: None,\n        };\n\n        // Cache miss\n        cache\n            .expect_get_cached_page()\n            .returning(|_| Ok(None));\n\n        // Repository returns 1 dummy record\n        repo.expect_fetch_page()\n            .returning(|_| {\n                Ok((\n                    vec![LedgerEntryView {\n                        id: Uuid::new_v4(),\n                        account_id: Uuid::new_v4(),\n                        amount: rust_decimal::Decimal::ONE,\n                        currency: \"USD\".into(),\n                        posted_at: Utc::now(),\n                        memo: None,\n                    }],\n                    1,\n                ))\n            });\n\n        // Cache should be asked to write\n        cache\n            .expect_cache_page()\n            .returning(|_, _| Ok(()));\n\n        let svc = LedgerEntryService::new(repo, cache);\n\n        let result = svc.get_paginated(sample_query).await.unwrap();\n\n        assert_eq!(result.total, 1);\n        assert!(!result.items.is_empty());\n    }\n}\n```", "numLines": 486, "startLine": 1, "totalLines": 486}}

