   139→/// Service façade orchestrating query workflow.
   140→pub struct CashFlowForecastService<R, C> {
   141→    repo: Arc<R>,
   142→    #[cfg(feature = "response_caching")]
   143→    cache: Arc<C>,
   144→    /// TTL for cache entries.
   145→    #[cfg(feature = "response_caching")]
   146→    ttl: Duration,
   147→}
   148→
   149→impl<R, C> CashFlowForecastService<R, C>
   150→where
   151→    R: CashFlowForecastRepository,
   152→{
   153→    pub fn new(repo: Arc<R>) -> Self
   154→    where
   155→        C: Default,
   156→    {
   157→        Self {
   158→            repo,
   159→            #[cfg(feature = "response_caching")]
   160→            cache: Arc::<C>::default(),
   161→            #[cfg(feature = "response_caching")]
   162→            ttl: Duration::from_secs(300),
   163→        }
   164→    }
   165→
   166→    #[cfg_attr(
   167→        feature = "response_caching",
   168→        instrument(
   169→            name = "CashFlowForecastService::get_forecast",
   170→            skip(self),
   171→            fields(account_id = %account_id, page = pagination.page, per_page = pagination.per_page)
   172→        )
   173→    )]
   174→    #[cfg_attr(
   175→        not(feature = "response_caching"),
   176→        instrument(
   177→            name = "CashFlowForecastService::get_forecast",
   178→            skip(self),
   179→            fields(account_id = %account_id, page = pagination.page, per_page = pagination.per_page)
   180→        )
   181→    )]
   182→    pub async fn get_forecast(
   183→        &self,
   184→        account_id: Uuid,
   185→        range: DateRange,
   186→        pagination: Pagination,
   187→        force_refresh: bool,
   188→    ) -> Result<CashFlowForecastPage, ServiceError>
   189→    where
   190→        C: CacheBackend,
   191→    {
   192→        range.validate()?;
   193→
   194→        #[cfg(feature = "response_caching")]
   195→        if !force_refresh {
   196→            if let Some(cached) = self
   197→                .cache
   198→                .get::<CashFlowForecastPage>(&CacheKey::new(
   199→                    account_id,
   200→                    range,
   201→                    pagination,
   202→                ))
   203→                .await?
   204→            {
   205→                debug!("cache hit for account_id={}", account_id);
   206→                return Ok(cached);
   207→            }
   208→        }
   209→
   210→        let span = tracing::info_span!("db_query");
   211→        let _enter = span.enter();
   212→        let started_at = Instant::now();
   213→        let (rows, total) = self
   214→            .repo
   215→            .list_by_account(account_id, range, pagination)
   216→            .await
   217→            .map_err(ServiceError::Repository)?;
   218→        debug!("db_query completed in {:?}", started_at.elapsed());
   219→
   220→        let page = CashFlowForecastPage {
   221→            items: rows.into_iter().map(Into::into).collect(),
   222→            total_items: total,
   223→            page: pagination.page.get(),
   224→            per_page: pagination.per_page.get(),
   225→        };
   226→
   227→        #[cfg(feature = "response_caching")]
   228→        {
   229→            self.cache
   230→                .set(
   231→                    CacheKey::new(account_id, range, pagination),
   232→                    &page,
   233→                    self.ttl,
   234→                )
   235→                .await?;
   236→        }
   237→
   238→        Ok(page)
   239→    }
   240→}
