   246→#[async_trait]
   247→pub trait CacheBackend: Send + Sync + 'static {
   248→    async fn get<T>(&self, key: &CacheKey) -> Result<Option<T>, CacheError>
   249→    where
   250→        T: for<'de> Deserialize<'de> + Send;
   251→    async fn set<T>(
   252→        &self,
   253→        key: CacheKey,
   254→        value: &T,
