   261→/// Typed cache-key guaranteeing stable hash/serialize logic.
   262→#[cfg(feature = "response_caching")]
   263→#[derive(Debug, Clone, Hash, PartialEq, Eq, Serialize)]
   264→pub struct CacheKey {
   265→    account_id: Uuid,
   266→    from: NaiveDate,
   267→    to: NaiveDate,
   268→    page: u32,
   269→    per_page: u32,
