    82→impl Pagination {
    83→    /// Tries to build a [`Pagination`] struct from an arbitrary query map,
    84→    /// returning validation errors early.
    85→    pub fn try_from_query_map(
    86→        params: &HashMap<String, String>,
    87→    ) -> Result<Self, PaginationError> {
    88→        let offset = params
    89→            .get("offset")
    90→            .and_then(|v| v.parse::<u32>().ok())
    91→            .unwrap_or_default();
