   114→/// The envelope returned by list-style endpoints.
   115→#[derive(Debug, Clone, Serialize)]
   116→pub struct Paginated<T>
   117→where
   118→    T: Serialize,
   119→{
   120→    pub items:       Vec<T>,
   121→    pub total:       u64,
   122→    pub offset:      u32,
   123→    pub limit:       u32,
   124→    pub has_more:    bool,
   125→    #[serde(skip_serializing_if = "Option::is_none")]
   126→    pub cache_hint:  Option<CacheHint>,
   127→}
   128→
   129→impl<T> Paginated<T>
   130→where
   131→    T: Serialize,
   132→{
   133→    pub fn new(
   134→        items: Vec<T>,
   135→        total: u64,
   136→        pagination: &Pagination,
   137→        cacheable: bool,
   138→    ) -> Self {
   139→        let has_more = (pagination.offset as u64 + items.len() as u64) < total;
   140→        let cache_hint = cacheable.then(|| CacheHint::new(DEFAULT_TTL_SECONDS));
   141→
   142→        Self {
   143→            items,
   144→            total,
   145→            offset:   pagination.offset,
   146→            limit:    pagination.limit,
   147→            has_more,
   148→            cache_hint,
   149→        }
   150→    }
   151→}
