   194→/// Row mapping for the `ledger_entries` table.  This is our **domain model**.
   195→/// (In reality the amount would likely be a decimal; using i64 for brevity.)
   196→#[derive(Debug, Clone, FromRow, Serialize)]
   197→pub struct LedgerEntry {
   198→    pub id:          Uuid,
   199→    pub account_id:  Uuid,
   200→    pub amount:      i64,             // amount in *minor* units (cents)
   201→    pub currency:    String,
   202→    pub description: Option<String>,
   203→    pub created_at:  DateTime<Utc>,
   204→}
