   206→/// Strongly-typed wrapper over *sqlx* PgPool implementing the
   207→/// [`PaginatedRepository`] trait for [`LedgerEntry`].
   208→pub struct LedgerEntryPgRepository {
   209→    pool: PgPool,
   210→}
   211→
   212→impl LedgerEntryPgRepository {
   213→    /// Allocate a new repository instance.
   214→    #[must_use]
