   220→#[async_trait]
   221→impl PaginatedRepository for LedgerEntryPgRepository {
   222→    type Output = LedgerEntry;
   223→
   224→    #[instrument(skip_all, name = "repo.ledger.list")]
   225→    async fn paginated_list(
   226→        &self,
   227→        pagination: &Pagination,
   228→    ) -> Result<Paginated<Self::Output>, PaginationError> {
   229→        // -------------------- Build the dynamic SQL query --------------------
   230→        // We expect an index on ( account_id, created_at DESC ) in production.
   231→        let mut builder: QueryBuilder<Postgres> =
   232→            QueryBuilder::new("SELECT * FROM ledger_entries ");
   233→
   234→        // Optional ORDER BY clause from the client — only allow whitelisted cols.
   235→        if let Some(sort_spec) = &pagination.sort {
   236→            match sort_spec.as_str() {
   237→                "created_at:asc"  => builder.push("ORDER BY created_at ASC "),
   238→                "created_at:desc" => builder.push("ORDER BY created_at DESC "),
   239→                "amount:asc"      => builder.push("ORDER BY amount ASC "),
   240→                "amount:desc"     => builder.push("ORDER BY amount DESC "),
   241→                _ => {
   242→                    return Err(PaginationError::Validation(
   243→                        ValidationError::new("invalid_sort").into(),
   244→                    ));
   245→                }
   246→            }
   247→        } else {
   248→            builder.push("ORDER BY created_at DESC ");
   249→        }
   250→
   251→        // Apply LIMIT / OFFSET
   252→        let (limit, offset) = pagination.sql_limit_offset();
   253→        builder.push("LIMIT ").push_bind(limit as i64).push(" ");
   254→        builder.push("OFFSET ").push_bind(offset as i64);
   255→
   256→        // --------------------- Execute the data query ------------------------
   257→        let entries: Vec<LedgerEntry> = builder
   258→            .build_query_as()
   259→            .fetch_all(&self.pool)
   260→            .await?;
   261→
   262→        // -------------------- Get the *total* record count -------------------
   263→        let total: (i64,) =
   264→            sqlx::query_as("SELECT COUNT(*) as count FROM ledger_entries")
   265→                .fetch_one(&self.pool)
   266→                .await?;
   267→
   268→        // ---------------------------------------------------------------------
   269→        Ok(Paginated::new(
   270→            entries,
   271→            total.0 as u64,
   272→            pagination,
   273→            /*cacheable=*/ true,
   274→        ))
   275→    }
   276→}
