   278→/// An *idempotent* command that inserts a ledger entry inside its own
   279→/// transaction.  Exposed as a convenience; not part of the trait.
   280→///
   281→/// Demonstrates how we keep read & write paths separated (`CQRS` style).
   282→impl LedgerEntryPgRepository {
   283→    #[instrument(skip_all, name = "repo.ledger.insert")]
   284→    pub async fn insert(&self, entry: &LedgerEntry) -> Result<(), PaginationError> {
   285→        let mut tx = self.pool.begin().await?;
   286→
   287→        sqlx::query(
   288→            r#"
   289→            INSERT INTO ledger_entries
   290→            (id, account_id, amount, currency, description, created_at)
   291→            VALUES ($1, $2, $3, $4, $5, $6)
   292→            ON CONFLICT (id) DO NOTHING
   293→            "#,
   294→        )
   295→        .bind(entry.id)
   296→        .bind(entry.account_id)
   297→        .bind(entry.amount)
   298→        .bind(&entry.currency)
   299→        .bind(&entry.description)
   300→        .bind(entry.created_at)
   301→        .execute(&mut tx)
   302→        .await?;
   303→
   304→        tx.commit().await?;
   305→        Ok(())
   306→    }
   307→}
