    71→/// Hard upper-bound for `per_page` to protect Redis payload size and memory
    72→/// pressure.  A single cached page must never exceed this many items.
    73→const MAX_PAGE_SIZE: usize = 250;
    74→
    75→/// Built-in soft time-to-live for cached pages.
    76→///
    77→/// Note: domain services may override this by providing
    78→/// `PagedCache::with_ttl`.
    79→const DEFAULT_TTL: Duration = Duration::from_secs(30);
    80→
    81→/// Redis channel used for fan-out invalidation events.
    82→const INVALIDATION_CHANNEL: &str = "ledgerlink:nexus:cache:evict";
    83→
    84→/// Common error envelope returned by this module.
    85→#[derive(Error, Debug)]
    86→pub enum CacheError {
    87→    #[error("redis error: {0}")]
    88→    Redis(#[from] redis::RedisError),
    89→    #[error("serialization error: {0}")]
    90→    Bincode(#[from] bincode::Error),
    91→    #[error("application error: {0}")]
    92→    Application(#[from] anyhow::Error),
    93→}
