    95→/// Pagination information sent by a caller or deserialized from a request
    96→/// payload.  It purposely mirrors the GraphQL “Connection” spec as well as the
    97→/// REST flavour used in our OpenAPI contract.
    98→#[derive(Clone, Copy, Debug, Serialize, Deserialize)]
    99→pub struct Pagination {
   100→    pub page: usize,
   101→    pub per_page: usize,
   102→}
   103→
   104→impl Pagination {
   105→    /// Construct a new pagination config while enforcing invariants.
   106→    pub fn new(page: usize, per_page: usize) -> Result<Self, CacheError> {
   107→        if per_page == 0 || per_page > MAX_PAGE_SIZE {
   108→            anyhow::bail!(
   109→                "per_page must be within 1..={MAX_PAGE_SIZE} (got {per_page})"
   110→            );
   111→        }
   112→        Ok(Self { page, per_page })
   113→    }
   114→}
