   116→/// Trait implemented by every Query object that wishes to leverage the cache.
   117→/// Only a handful of methods are required so the domain code remains
   118→/// decoupled from Redis.
   119→#[async_trait]
   120→pub trait CacheableQuery: Send + Sync {
   121→    /// A tenant-scoped uuid allowing sharding and event fan-out.
   122→    fn tenant_id(&self) -> Uuid;
   123→
   124→    /// Pagination info (page number + page size)
   125→    fn pagination(&self) -> &Pagination;
   126→
   127→    /// Deterministic hash that uniquely identifies the query parameters
   128→    /// **excluding** pagination (e.g. account, date_range, filters).
   129→    ///
   130→    /// Think of this as a stable, human-readable identifier.
   131→    fn cache_hash(&self) -> String;
   132→}
   133→
   134→/// Envelope stored in Redis.  We prepend a short version tag so we can bump
   135→/// serialization format without flushing the whole store.
   136→#[derive(Debug, Serialize, Deserialize)]
   137→struct CachedEnvelope<T> {
   138→    v: u8,
   139→    data: T,
   140→}
   141→
   142→/// A concrete Redis-backed cache aware of pagination and invalidation events.
   143→pub struct PagedCache<T> {
   144→    conn: ConnectionManager,
   145→    ttl: Duration,
   146→    /// Broadcast channel used locally for best-effort, in-process fan-out.
   147→    evict_tx: broadcast::Sender<String>,
   148→    _phantom: std::marker::PhantomData<T>,
   149→}
   150→
   151→impl<T> PagedCache<T>
   152→where
   153→    T: Serialize + DeserializeOwned + Send + Sync + 'static,
   154→{
   155→    /// Connect to Redis and spawn a small background task listening for
   156→    /// invalidation events.
   157→    pub async fn connect(redis_url: &str) -> Result<Self, CacheError> {
   158→        let client = redis::Client::open(redis_url)?;
   159→        let manager = ConnectionManager::new(client).await?;
   160→        let (tx, _rx) = broadcast::channel(64);
   161→
   162→        // Spawn invalidation listener
   163→        Self::spawn_invalidator(redis_url.to_owned(), tx.clone());
   164→
   165→        Ok(Self {
   166→            conn: manager,
   167→            ttl: DEFAULT_TTL,
   168→            evict_tx: tx,
   169→            _phantom: std::marker::PhantomData,
   170→        })
   171→    }
   172→
   173→    /// Provide a custom TTL.  Fluent-style builder.
   174→    pub fn with_ttl(mut self, ttl: Duration) -> Self {
   175→        self.ttl = ttl;
   176→        self
   177→    }
   178→
   179→    /// Try to fetch from cache or execute `fetch_fn` and then cache the
   180→    /// outcome.  The second value in the tuple indicates whether it was
   181→    /// a cache hit.
   182→    #[instrument(skip_all, fields(cache.key = %self.derive_key(query)))]
   183→    pub async fn get_or_query<Q, F, E>(
   184→        &self,
   185→        query: &Q,
   186→        fetch_fn: F,
   187→    ) -> Result<(T, bool), CacheError>
   188→    where
   189→        Q: CacheableQuery,
   190→        F: std::future::Future<Output = Result<T, E>> + Send,
   191→        E: Into<anyhow::Error> + Send,
   192→    {
   193→        let redis_key = self.derive_key(query);
   194→        // 1. Optimistic local in-process check first
   195→        if let Ok(value) = self.try_get_local(&redis_key).await {
   196→            return Ok((value, true));
   197→        }
   198→
   199→        // 2. Grab from Redis
   200→        let mut conn = self.conn.clone();
   201→        if let Some(raw): Option<Vec<u8>> = conn.get(&redis_key).await? {
   202→            let envelope: CachedEnvelope<T> = bincode::deserialize(&raw)?;
   203→            // No versioning strategy yet, v=0
   204→            debug!("Cache hit (redis)");
   205→            self.populate_local(redis_key.clone(), envelope.data.clone())
   206→                .await;
   207→            return Ok((envelope.data, true));
   208→        }
   209→
   210→        // 3. Miss – execute provided closure
   211→        debug!("Cache miss; delegating to fetch_fn");
   212→        let fresh = fetch_fn.await.map_err(Into::into)?;
   213→
   214→        // 4. Save to Redis (fire-and-forget)
   215→        let save_redis_key = redis_key.clone();
   216→        let save_ttl = self.ttl;
   217→        let save_value = fresh.clone();
   218→        tokio::spawn(async move {
   219→            let env = CachedEnvelope { v: 0, data: save_value };
   220→            if let Ok(payload) = bincode::serialize(&env) {
   221→                let _: Result<(), _> = conn
   222→                    .set_ex(save_redis_key, payload, save_ttl.as_secs() as usize)
   223→                    .await;
   224→            }
   225→        });
   226→
   227→        // 5. Fill local cache
   228→        self.populate_local(redis_key, fresh.clone()).await;
   229→        Ok((fresh, false))
   230→    }
   231→
   232→    /// Explicitly evict a query result (all pages) for the given tenant/query
   233→    /// hash, broadcasting the event to every service instance.
   234→    ///
   235→    /// Should be called by the *Command* side whenever a mutation might
   236→    /// invalidate read models (e.g. posting a new ledger entry).
   237→    pub async fn evict<Q>(&self, query: &Q) -> Result<(), CacheError>
   238→    where
   239→        Q: CacheableQuery,
   240→    {
   241→        let pattern = format!("nexus:{}:{}:*", query.tenant_id(), query.cache_hash());
   242→        let mut conn = self.conn.clone();
   243→        let _: () = redis::cmd("UNLINK").arg(pattern.clone()).query_async(&mut conn).await?;
   244→
   245→        // Broadcast
   246→        let _ = conn.publish::<_, _, ()>(INVALIDATION_CHANNEL, pattern.clone()).await;
   247→        // Local channel
   248→        let _ = self.evict_tx.send(pattern);
   249→
   250→        Ok(())
   251→    }
   252→
   253→    /// Assemble the final Redis key
   254→    fn derive_key<Q: CacheableQuery>(&self, query: &Q) -> String {
   255→        format!(
   256→            "nexus:{}:{}:{}:{}",
   257→            query.tenant_id(),
   258→            query.cache_hash(),
   259→            query.pagination().page,
   260→            query.pagination().per_page
   261→        )
   262→    }
   263→
   264→    // ──────────────────────────────────────────────────────────────────────────
   265→    // Local in-process cache (tiny, bounded, non-blocking)
   266→    // -------------------------------------------------------------------------
   267→
   268→    async fn try_get_local(&self, k: &str) -> Result<T, CacheError> {
   269→        use moka::future::Cache;
   270→        static LOCAL: once_cell::sync::Lazy<Cache<String, Bytes>> =
   271→            once_cell::sync::Lazy::new(|| Cache::builder()
   272→                .max_capacity(4_096)
   273→                .time_to_live(DEFAULT_TTL)
   274→                .build());
   275→
   276→        if let Some(bytes) = LOCAL.get(k).await {
   277→            let env: CachedEnvelope<T> = bincode::deserialize(bytes.as_ref())?;
   278→            return Ok(env.data);
   279→        }
   280→        anyhow::bail!("not in local cache")
   281→    }
   282→
   283→    async fn populate_local(&self, k: String, data: T) {
   284→        use moka::future::Cache;
   285→        static LOCAL: once_cell::sync::Lazy<Cache<String, Bytes>> =
   286→            once_cell::sync::Lazy::new(|| Cache::builder()
   287→                .max_capacity(4_096)
   288→                .time_to_live(DEFAULT_TTL)
   289→                .build());
   290→
   291→        if let Ok(payload) = bincode::serialize(&CachedEnvelope { v: 0, data }) {
   292→            let _ = LOCAL.insert(k, Bytes::from(payload)).await;
   293→        }
   294→    }
   295→
   296→    // ──────────────────────────────────────────────────────────────────────────
   297→    // Background Redis pub/sub listener – distribute invalidation events
   298→    // -------------------------------------------------------------------------
   299→
   300→    fn spawn_invalidator(redis_url: String, evict_tx: broadcast::Sender<String>) {
   301→        tokio::spawn(async move {
   302→            loop {
   303→                match redis::Client::open(redis_url.as_str())
   304→                    .and_then(|c| c.get_async_connection())
   305→                    .await
   306→                {
   307→                    Ok(conn) => {
   308→                        if let Err(e) = Self::listen_invalidation(conn, evict_tx.clone()).await {
   309→                            warn!(error = %e, "cache invalidation listener died; restarting");
   310→                        };
   311→                    }
   312→                    Err(e) => {
   313→                        warn!(error = %e, "cannot connect to redis for invalidation; retrying");
   314→                        time::sleep(Duration::from_secs(5)).await;
   315→                    }
   316→                }
   317→            }
   318→        });
   319→    }
   320→
   321→    async fn listen_invalidation(
   322→        mut conn: redis::aio::Connection,
   323→        evict_tx: broadcast::Sender<String>,
   324→    ) -> Result<(), CacheError> {
   325→        use redis::AsyncCommands;
   326→
   327→        let mut pubsub = conn.as_pubsub();
   328→        pubsub.subscribe(INVALIDATION_CHANNEL).await?;
   329→
   330→        loop {
   331→            let msg = pubsub.on_message().await;
   332→            let payload: String = msg.get_payload()?;
   333→            // Re-emit into local broadcast
   334→            let _ = evict_tx.send(payload.clone());
   335→
   336→            // Purge local moka cache entries matching the pattern
   337→            Self::purge_local_matching(&payload).await;
   338→        }
   339→    }
   340→
   341→    async fn purge_local_matching(pattern: &str) {
   342→        use moka::future::Cache;
   343→        static LOCAL: once_cell::sync::Lazy<Cache<String, Bytes>> =
   344→            once_cell::sync::Lazy::new(|| Cache::builder()
   345→                .max_capacity(4_096)
   346→                .time_to_live(DEFAULT_TTL)
   347→                .build());
   348→
   349→        let keys: Vec<String> = LOCAL.iter().map(|(k, _)| k.clone()).collect();
   350→        for k in keys {
   351→            if k.starts_with(pattern) {
   352→                LOCAL.invalidate(&k).await;
   353→            }
   354→        }
   355→    }
   356→}
